#include <iostream>
#include <cmath>

int factorize(int number) {
    int count = 0;
    while (number % 2 == 0) {
        number /= 2;
        count++;
    }
    int sqrtNum = sqrt(number);
    for (int i = 3; i <= sqrtNum; i += 2) {
        while (number % i == 0) {
            number /= i;
            count++;
        }
    }
    if (number > 2) {
        count++;
    }
    return count;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        int num;
        std::cin >> num;
        std::cout << factorize(num) << std::endl;
    }
    return 0;
},1

