#include <iostream>
#include <vector>
#include <unordered_map>

using namespace std;

unordered_map<int, int> dp;

int fact(int n, int m) {
    if (n < m)
        return 0;
    if (n == m)
        return 1;
    if (dp.find(n) != dp.end())
        return dp[n];
    int sum = 0;
    for (int i = m; i < n; i++)
        if (n % i == 0)
            sum += fact(n / i, i);
    dp[n] = sum;
    return sum;
}

int main() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; i++)
        cin >> a[i];
    for (int i = 0; i < n; i++)
        cout << fact(a[i], 2) << endl;
    return 0;
},1

#include <iostream>
#include <cmath>

int solve(int x, int divisor = 2) {
    if (x < 2) return 0;
    if (x == 2) return 1;
    if (x % divisor != 0) return solve(x, divisor + 1);
    int count = 1;
    int quotient = x / divisor;
    if (quotient >= divisor) {
        count += solve(quotient, divisor);
    }
    return count + solve(x, divisor + 1);
}

int main() {
    int n, number;
    std::cin >> n;
    while (n--) {
        std::cin >> number;
        std::cout << solve(number) << std::endl;
    }
    return 0;
},1

