int solve(int k, int n) {
    int count = 1;
    if (n == 2 || n == 3)
        return count;
    else {
        int c = sqrt(n);
        for (int i = k; i <= c; i++)
            if (n % i == 0)
                count += solve(i, n / i);
        return count;
    }
}

