// Function to count the factors of a number
int countFactors(int number) {
    int count = 0;
    for (int i = 2; i <= sqrt(number); i++) {
        while (number % i == 0) {
            number /= i;
            count++;
        }
    }
    if (number > 1) count++;
    return count;
}

