int part(int x, int t) {
    int number = 0;
    if (x == 1)
        return 0;
    if (x == 2)
        return 1;
    for (int i = t; i <= sqrt(x); i++) {
        if (x % i == 0) {
            number += part(x / i, i);
        }
    }
    return number;
}

