#include <iostream>
#include <cmath>

int countFactors(int number, int minFactor) {
    int factorCount = 0;
    int sqrtNumber = static_cast<int>(sqrt(static_cast<double>(number)));

    for (int factor = minFactor; factor <= sqrtNumber; ++factor) {
        if (number % factor == 0) {
            factorCount++;
            factorCount += countFactors(number / factor, factor);
        }
    }

    return factorCount;
}

int main() {
    int testCases;
    std::cin >> testCases;

    while (testCases--) {
        int number;
        std::cin >> number;
        std::cout << countFactors(number, 2) + 1 << std::endl;
    }

    return 0;
},1

