// Function to calculate the number of divisors
int countDivisors(int n) {
    int count = 0;
    for(int i = 1; i <= std::sqrt(n); i++) {
        if(n % i == 0) {
            // If divisors are equal, count only one
            if(n / i == i)
                count++;
            else // Otherwise count both
                count += 2;
        }
    }
    return count;
}

// Main function
int main() {
    int n, num;
    std::cin >> n;
    while(n--) {
        std::cin >> num;
        std::cout << countDivisors(num) << std::endl;
    }
    return 0;
},1

