// Function to calculate the sum of factors
int sumFactors(int number) {
    int sum = 0;
    for (int i = 1; i <= sqrt(number); ++i) {
        if (number % i == 0) {
            if (number / i == i) {
                sum += i;
            } else {
                sum += i;
                sum += number / i;
            }
        }
    }
    return sum;
}

int main() {
    int n;
    std::cin >> n;
    while (n--) {
        int a;
        std::cin >> a;
        std::cout << sumFactors(a) << std::endl;
    }
    return 0;
},1

