#include <iostream>
#include <cmath>

class FactorCounter {
    private:
        int count;
        void countFactors(int num, int div) {
            if (num == 1) return;
            if (num % div == 0) {
                count++;
                countFactors(num / div, div);
            } else {
                countFactors(num, div + 1);
            }
        }
    public:
        int getCount(int num) {
            count = 0;
            countFactors(num, 2);
            return count;
        }
};

int main() {
    FactorCounter fc;
    int n, m;
    std::cin >> m;
    for (int i = 0; i < m; i++) {
        std::cin >> n;
        std::cout << fc.getCount(n) << std::endl;
    }
    return 0;
},1

#include <iostream>
using namespace std;

int decompose(int n, int k) {
    if (n == 1) return 1;
    int res = 0;
    for (int i = k; i <= n; ++i) {
        if (n % i == 0) {
            res += decompose(n / i, i);
        }
    }
    return res;
}

int main() {
    int times;
    cin >> times;
    while(times--) {
        int n;
        cin >> n;
        cout << decompose(n, 2) << endl;
    }
    return 0;
},1

#include <iostream>
#include <vector>

using namespace std;

void findDivisors(int num, int divisor, vector<int>& divisors) {
    if (num == divisor) {
        divisors.push_back(divisor);
    } else {
        for (int i = divisor; i <= num / divisor; ++i) {
            if (num % (i * divisor) == 0) {
                findDivisors(i * divisor, i, divisors);
            }
        }
    }
}

int main() {
    int n;
    cin >> n;

    for (int i = 0; i < n; ++i) {
        int num;
        cin >> num;

        vector<int> divisors;
        for (int j = 2; j <= num; ++j) {
            if (num % j == 0) {
                findDivisors(num, j, divisors);
            }
        }

        cout << divisors.size() << endl;
    }

    return 0;
},1

