// Function to check if the number is prime
bool isPrime(int num) {
    if (num <= 1) {
        return false;
    }
    for (int i = 2; i * i <= num; i++) {
        if (num % i == 0) {
            return false;
        }
    }
    return true;
}

// Function to count the number of divisors
int countDivisors(int num) {
    int count = 0;
    for (int i = 1; i <= num; i++) {
        if (num % i == 0) {
            count++;
        }
    }
    return count;
}

// Main function
int main() {
    int n;
    std::cin >> n;

    while (n--) {
        int a;
        std::cin >> a;
        if (isPrime(a)) {
            std::cout << countDivisors(a) << std::endl;
        } else {
            std::cout << countDivisors(a) - 1 << std::endl;
        }
    }

    return 0;
},1

