int factorize(int number, int start) {
    int i, sum = 1;
    if (start == number)
        sum = 1;
    else {
        for (i = start; i <= sqrt(number); i++) {
            if (number % i == 0) {
                sum += factorize(number / i, i);
            }
        }
    }
    return sum;
}

