#include <iostream>
#include <cmath>

bool isPrime(int k) {
    if (k == 2) return true;
    else {
        int sqrt_k = sqrt(k);
        for (int j = 2; j <= sqrt_k; j++) {
            if (k % j == 0) return false;
        }
        return true;
    }
}

int countDivisors(int a, int b) {
    if (a == b) return 1;
    if (a > b) return 0;

    int count = 0;
    for (int i = a; i <= b; i++) {
        if (b % i == 0) {
            count += countDivisors(i, b / i);
        }
    }
    return count;
}

int main() {
    int Time;
    std::cin >> Time;
    while (Time > 0) {
        int n;
        std::cin >> n;
        std::cout << countDivisors(2, n) << std::endl;
        Time--;
    }
    return 0;
},1

