#include <cmath>

int decompose(int x, int y);

int main() {
    int n, m;
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        std::cin >> m;
        std::cout << decompose(m, 2) << std::endl;
    }
    return 0;
}

int decompose(int x, int y) {
    int sum = 0;
    int b = sqrt(x);
    if (x == 1) return 0;
    for (int i = y; i <= b; i++) {
        if (x % i == 0) {
            sum += decompose(x / i, i);
        }
    }
    return sum + 1;
},1

