using namespace std;

class Solution {
private:
    vector<int> factors;
    int num;

    void findFactors(int n, int divisor) {
        if (n == 1)
            return;

        while (n % divisor == 0) {
            factors.push_back(divisor);
            n /= divisor;
        }

        if (n > 1)
            findFactors(n, divisor + 1);
    }

public:
    int countDivisors(int n) {
        num = 0;
        findFactors(n, 2);

        for (int factor : factors)
            num += countDivisors(factor);

        return num;
    }
};

int main() {
    Solution sol;
    int n;
    cin >> n;

    for (int i = 0; i < n; i++) {
        int num;
        cin >> num;
        cout << sol.countDivisors(num) << endl;
    }

    return 0;
},1

