int computeSum(int number, int divisor) {
    int sum = 0;
    while (number % divisor == 0) {
        sum += divisor;
        number /= divisor;
    }
    return sum;
}

int solve(int number) {
    int sum = 0;
    int sqrtNum = sqrt(number);

    for (int i = 2; i <= sqrtNum; ++i) {
        sum += computeSum(number, i);
    }

    return sum;
}

