// Function to calculate the sum of divisors
int sum_of_divisors(int n) {
    int count = 0;
    int j = 2;

    while (n != 1) {
        if (n % j == 0) {
            count++;
            n /= j;
        } else {
            j++;
        }
    }

    return count;
}

