using namespace std;

bool isPrime(int num) {
    if (num <= 1)
        return false;
    int sqrtNum = sqrt(num);
    for (int i = 2; i <= sqrtNum; i++) {
        if (num % i == 0)
            return false;
    }
    return true;
}

int countPrimeFactors(int num) {
    int count = 0;
    for (int i = 2; i <= sqrt(num); i++) {
        if (num % i == 0) {
            if (isPrime(i)) {
                count++;
            }
            if (isPrime(num / i) && num / i != i) {
                count++;
            }
        }
    }
    return count;
}

int main() {
    int number, cases;
    cin >> cases;
    while (cases--) {
        cin >> number;
        cout << countPrimeFactors(number) << endl;
    }
    return 0;
