#include <iostream>
#include <vector>

struct Node {
    int value;
    int count;
};

std::vector<Node> initializeNodes(int n) {
    std::vector<Node> nodes(n);
    for(int i = 0; i < n; ++i) {
        nodes[i].value = 0;
        nodes[i].count = 0;
    }
    return nodes;
}

void updateNodes(std::vector<Node>& nodes, int number) {
    for(int i = 2; i <= number; ++i) {
        if(number % i == 0) {
            for(int j = i; j <= number; j += i) {
                nodes[j - 2].value = i;
                nodes[j - 2].count++;
            }
        }
    }
}

int countDivisors(const std::vector<Node>& nodes) {
    int count = 0;
    for(const auto& node : nodes) {
        if(node.value != 0 && node.value != node.count) {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, number;
    std::cin >> n;
    std::vector<int> results;

    for(int i = 0; i < n; ++i) {
        std::cin >> number;
        std::vector<Node> nodes = initializeNodes(number);
        updateNodes(nodes, number);
        results.push_back(countDivisors(nodes));
    }

    for(const auto& result : results) {
        std::cout << result << "\n";
    }

    return 0;
},1

