using namespace std;

void decompose(int number, int divisor, vector<int>& factors) {
    if (number % divisor == 0) {
        factors.push_back(divisor);
        decompose(number / divisor, divisor, factors);
    } else {
        if (divisor * divisor > number) {
            if (number != 1)
                factors.push_back(number);
            return;
        }
        decompose(number, divisor + 1, factors);
    }
}

int calculateSumOfFactors(int number) {
    vector<int> factors;
    decompose(number, 2, factors);
    int sum = 0;
    for (int factor : factors) {
        sum += factor * (pow(2, factors.size() / factor) - 1);
    }
    return sum;
}

int main() {
