void countFactors(int number, int divisor, int& count) {
    if (number == 1) {
        return;
    }
    if (number % divisor == 0) {
        count++;
        while (number % divisor == 0) {
            number /= divisor;
        }
    }
    for (int nextDivisor = divisor + 1; nextDivisor * nextDivisor <= number; ++nextDivisor) {
        countFactors(number, nextDivisor, count);
        break;
    }
}

