// Function to calculate the sum of divisors using dynamic programming
int sumOfDivisors(int num, int start) {
    static vector<vector<int>> memo(40001, vector<int>(201));

    if (memo[num][start] != 0)
        return memo[num][start];

    if (num < start)
        return 0;

    int sum = 1; // Start with 1 as a divisor for all numbers
    for (int i = start; i <= sqrt(num); ++i) {
        if (num % i == 0) {
            sum += i;
            if (i != num / i)
                sum += num / i;
        }
    }

    memo[num][start] = sum;
    return sum;
}

