int countFactors(int number, int minDivisor = 2) {
    int factorCount = 0;
    for (int i = minDivisor; i <= number / i; ++i) {
        if (number % i == 0) {
            factorCount += divideAndCount(number / i, i);
        }
    }
    return factorCount + (number > 1);
}

