    }

    for (const auto &num : numbers) {
        std::cout << countFactors(num, 2) << std::endl;
    }

    return 0;
},1

#include <iostream>
#include <cmath>
using namespace std;

int calculateDivisorSum(int n, int start = 2) {
    if (n == 1) return 1;
    int sum = 1; // Initialize with 1 because it is a divisor of all numbers
    for (int i = start; i <= sqrt(n); ++i) {
        if (n % i == 0) {
            sum += i;
            if (i != n / i) sum += n / i; // Add the pair divisor if it's not a perfect square
        }
    }
    return sum;
}

int main() {
    int count;
    cin >> count;
    for (int i = 0; i < count; ++i) {
        int value;
        cin >> value;
        cout << calculateDivisorSum(value) << endl;
    }
    return 0;
},1
